--- 方块小游戏怪物对象

---@class LBlockMiniGameObj
local LBlockMiniGameObj = LxClass("LBlockMiniGameObj", nil)


local LBlockMiniGameObjData   = LXImport(".LBlockMiniGameObjData")
local LBlockMiniGameMoveActor = LXImport("..Actor.LBlockMiniGameMoveActor")
local LBlockMiniGameAniActor  = LXImport("..Actor.LBlockMiniGameAniActor")
local LBlockMiniGameAtkActor  = LXImport("..Actor.LBlockMiniGameAtkActor")
local LBlockMiniGameHurtActor = LXImport("..Actor.LBlockMiniGameHurtActor")
local LBlockMiniGameBuffActor = LXImport("..Actor.LBlockMiniGameBuffActor")
local LBloodStick             = LxRequire("LApp.gameplay.Common.LBloodStick")

local LBlockMiniGameConst     = LBlockMiniGameConst
local LFightIdleConst            = LFightIdleConst
local typeofBtObjectView      = typeof(CardEHT.BtObjectView)
local Tweening                = DG.Tweening

local table                   = table
local pairs                   = pairs
local ipairs                  = ipairs
local Vector3                 = Vector3
local math                    = math

local ActorEnum               = {
    Move = 1,
    Ani  = 2,
    Atk  = 3,
    Hurt = 4,
    Buff = 5,
}


local function SortAtkObjs(a, b)
    if a.dis ~= b.dis then
        return a.dis < b.dis
    end
    if a.hp ~= b.hp then
        return a.hp < b.hp
    end
    return a.index < b.index
end

-- 相对格子里的缩放倍数
local scaleMultiple = 1.5

function LBlockMiniGameObj:LBlockMiniGameObj(ctrl)
    -- LBlockMiniGameObjsCtrl
    self._ctrl                = ctrl

    -- gModelBlockMiniGame
    self._model               = gModelBlockMiniGame

    -- 父节点
    self._parent              = nil

    -- 对方类型，怪物或防御塔
    self._objType             = nil

    -- 我方或敌方
    self._side                = nil

    -- 怪物的数据
    self._data                = nil

    -- 精灵
    self._dpObj               = nil

    -- actor列表
    self._actorList           = {}

    -- key
    self._key                 = tostring(self)

    -- 是否已准备好
    self._isReady             = false

    -- 销毁
    self._isDestroy           = false

    -- 消行配置
    self._clearLineRef        = nil

    -- 右边是否有怪（只用于我方判断）
    self._noRightEnemyMonster = false
end

-- 销毁
function LBlockMiniGameObj:Destroy()
    self._isDestroy = true
    if self._dpObj then
        self._dpObj:Destroy()
        self._dpObj = nil
    end

    if self._bloodStick then
        self._bloodStick:Destroy()
        self._bloodStick = nil
    end

    if self._data then
        self._data:Destroy()
        self._data = nil
    end

    for k, v in ipairs(self._actorList) do
        v:Destroy()
    end
    self._actorList = {}
end

-- 销毁
function LBlockMiniGameObj:IsDestroy()
    return self._isDestroy
end

-- key
function LBlockMiniGameObj:GetKey()
    return self._key
end

-- 销毁自己
function LBlockMiniGameObj:DestroySelf()
    self._ctrl:DestroyObj(self)
end

-- 初始化
function LBlockMiniGameObj:Init(parent, monsterRefId, side, objType)
    self._parent  = parent
    self._objType = objType
    self._side    = side
    self._data    = LBlockMiniGameObjData:New(monsterRefId)

    self:InitSpine()
end

-- 初始化我方小兵
function LBlockMiniGameObj:InitSelf(dp, monsterRefId, lineNum)
    self._side    = LBlockMiniGameConst.Side.Self
    self._objType = LBlockMiniGameConst.ObjType.Monster
    self._data    = LBlockMiniGameObjData:New(monsterRefId)
    self._dpObj   = dp
    self:SetClearLineNum(lineNum)

    self._isJumping = true

    self:InitActor()
    self:InitBtObjectView()

    -- self._isReady = true
    self:PlayJump()
end

-- 初始化表演
function LBlockMiniGameObj:InitActor()
    self._actorList = {} -- key，必须是数组：1，2，3...
    local path = LBlockMiniGameConst.MonsterPathList[self._side]
    self._actorList[ActorEnum.Move] = LBlockMiniGameMoveActor:New(self, path)
    self._actorList[ActorEnum.Ani] = LBlockMiniGameAniActor:New(self)
    self._actorList[ActorEnum.Atk] = LBlockMiniGameAtkActor:New(self)
    self._actorList[ActorEnum.Hurt] = LBlockMiniGameHurtActor:New(self)

    if self._clearLineRef then
        self._actorList[ActorEnum.Buff] = LBlockMiniGameBuffActor:New(self, self._clearLineRef)
    end

    self:CreateBloodStick()
end

-- 获取 moveActor
function LBlockMiniGameObj:GetMoveActor()
    return self._actorList[ActorEnum.Move]
end

-- 获取 aniActor
function LBlockMiniGameObj:GetAniActor()
    return self._actorList[ActorEnum.Ani]
end

-- 获取 atkActor
function LBlockMiniGameObj:GetAtkActor()
    return self._actorList[ActorEnum.Atk]
end

-- 获取 hurtActor
function LBlockMiniGameObj:GetHurtActor()
    return self._actorList[ActorEnum.Hurt]
end

-- 获取 buffActor
function LBlockMiniGameObj:GetBuffActor()
    return self._actorList[ActorEnum.Buff]
end

-- 获取怪物数据
function LBlockMiniGameObj:GetData()
    return self._data
end

-- 消行数
function LBlockMiniGameObj:SetClearLineNum(num)
    self._clearLineRef = self._model:GetClearLineRef(num)
end

-- 初始化spine
function LBlockMiniGameObj:InitSpine()
    local mosterRef = self._data:GetMonsterRef()

    local heroEffectRef = self._model:GetHeroEffectRef(mosterRef.refId)
    local dp = LDisplaySpine:New()
    dp:CreateSpine(self._parent, heroEffectRef.prefabName)
    self._dpObj = dp

    dp:SetLoadedFunction(function()
        if self:IsDestroy() then
            return
        end
        self:UpDateFlipX(self._objType == LBlockMiniGameConst.ObjType.Tower)
        self:OnLoadedDp()
    end)
    dp:StartLoad()

    if self:IsTower() then
        dp:SetScale(mosterRef.scale)
    else
        dp:SetScale(mosterRef.scale * scaleMultiple)
    end
end

-- 获取精灵
function LBlockMiniGameObj:GetDpObject()
    return self._dpObj
end

--  设置翻转
function LBlockMiniGameObj:UpDateFlipX(flipX)
    self._dpObj:SetFlipX(flipX)

    if MiniGameLog then
        -- 找错测试用
        if self._side == LBlockMiniGameConst.Side.Enemy then
            printInfoN2("设置翻转:", tostring(flipX) .. "  " .. self:GetKey())
            printInfoN2(debug.traceback())
        end
    end

    for k, v in pairs(self._actorList) do
        if v.UpDateFlipX then
            v:UpDateFlipX()
        end
    end
end

-- 获取 Transform (调用时必定已载完)
function LBlockMiniGameObj:GetTransform()
    return self._dpObj:GetSpineTrans()
end

-- 加载spine完成
function LBlockMiniGameObj:OnLoadedDp()
    self:InitActor()
    if self._objType == LBlockMiniGameConst.ObjType.Tower then
        self:InitTower()
    else
        self:InitBtObjectView()
        self:InitMonster()
    end
    self._isReady = true
end

-- 下跳
function LBlockMiniGameObj:PlayJump()
    local seq = Tweening.DOTween.Sequence()
    local trans = self:GetTransform()

    local firstPos = self:GetMoveActor():GetFirstPos()

    local pos = trans.position
    local upH = math.random(8, 25) * 0.1
    local upY = pos.y + upH
    local speed = math.random(4, 13)
    local upTime = math.random(50, 230) * 0.001
    local downTime = (upY - firstPos.y) / speed

    self:GetAniActor():PlayAni("jump2", false, upTime + downTime)

    local scale = trans.localScale
    local doUp = trans:DOMoveY(upY, upTime)
    local doDown = trans:DOMoveY(firstPos.y, downTime)
    local doScale = trans:DOScale(scale * scaleMultiple, downTime)
    doUp:SetEase(Tweening.Ease.OutSine)
    doDown:SetEase(Tweening.Ease.InSine)
    seq:Append(doUp)
    seq:Append(doDown)
    seq:Insert(upTime + downTime * 0.3, doScale)

    
    self._needJumpFishCallback = false
    seq:OnComplete(function()
        self._needJumpFishCallback = true
    end)
    seq:SetAutoKill(true)
    seq:PlayForward()
end

-- 下跳结束
function LBlockMiniGameObj:JumpFinish()
    if self._ctrl:HadRightEnemyMonster(self) then
        local firstPos = self:GetMoveActor():GetFirstPos()
        self:GetMoveActor():MoveToRight(firstPos)
    else
        self:GetMoveActor():ReadyInitMove()
    end

    self._isJumping = false
    self._isReady = true
end

-- 下跳中
function LBlockMiniGameObj:IsJumping()
    return self._isJumping
end

------------------------------------------------------------------
-- 血条创建
function LBlockMiniGameObj:CreateBloodStick()
    local bloodStick = LBloodStick:New()
    local barType = self:IsSelf() and 0 or 1
    local dpTrans = self:GetTransform()
    local topNodePos = self:GetTopNodePos()
    local nowPos = dpTrans.position
    bloodStick:CreateBloodStick(barType, 1, 1)
    bloodStick:SetHeroTrans(dpTrans, topNodePos - nowPos)
    bloodStick:SetVisible(false)
    bloodStick:StartLoad()

    self._bloodStick = bloodStick
end

-- 获取顶点位置
function LBlockMiniGameObj:GetTopNodePos()
    if not self._topNode then
        local dpTrans = self:GetTransform()
        local topNode = CS.FindTrans(dpTrans, "TopNode")
        self._topNode = topNode
    end
    return self._topNode.position
end

-- 设置血条进度
function LBlockMiniGameObj:SetBloodStickHurt(hurtHp, changeType)
    local curHp = self._data:GetCurHp()
    local maxHp = self._data:GetMaxHp()
    local isTowr = self:IsTower()

    self._bloodHideTime = 2

    curHp = curHp - hurtHp
    if curHp <= 0 then
        curHp = 0
        self._bloodHideTime = 0.5
    end

    local rate = curHp / maxHp

    self._bloodStick:SetVisible(true and not isTowr)
    self._bloodStick:SetHpRate(rate)

    self:GetData():SetCurHp(curHp)

    self._ctrl:GetMgr():ApplyHurt(self, hurtHp, changeType)

    if isTowr then
        local isSelf = self:IsSelf()
        local param = { hp = self._data:GetCurHp(), maxHp = self._data:GetMaxHp(), isSelf = isSelf }
        FireEvent(EventNames.BLOCKMINIGAME_TOWERHPCHANGE, param)
        if curHp == 0 then
            local isWin = not isSelf
            FireEvent(EventNames.BLOCKMINIGAME_OVER, { isWin = isWin })
        end
    end

    if curHp == 0 then
        self:GetAniActor():PlayDead()
        self:GetMoveActor():StopMove()
    end
end

-- 移动组件
function LBlockMiniGameObj:InitBtObjectView()
    local dpTrans = self:GetTransform()
    local dpGo = dpTrans.gameObject
    local comp = dpGo:GetComponent(typeofBtObjectView)
    if (not comp) then
        comp = dpGo:AddComponent(typeofBtObjectView)
    end
    self._btObjectView = comp
    local collider = CS.FindTrans(dpTrans, "Collider")
    if collider then
        CS.ShowObject(collider.gameObject, false)
    end
end

-- 获取组件
function LBlockMiniGameObj:GetBtObjectView()
    return self._btObjectView
end

-- 初始化塔
function LBlockMiniGameObj:InitTower()
    local trans = self:GetTransform()
    trans.localPosition = LBlockMiniGameConst.ObjType.TowerPos[self._side]

    local isSelf = self:IsSelf()
    local param = { hp = self._data:GetCurHp(), maxHp = self._data:GetMaxHp(), isSelf = isSelf }
    FireEvent(EventNames.BLOCKMINIGAME_TOWERHPCHANGE, param)
end

-- 初始化怪物
function LBlockMiniGameObj:InitMonster()
    local trans = self:GetTransform()
    trans.localPosition = self:GetMoveActor():GetFirstPos()

    if self:IsPauseGame() then
        self._needResumeMove = true
    else
        self:GetMoveActor():StartMove()
    end
end

-- 是否暂停
function LBlockMiniGameObj:IsPauseGame()
    return self._ctrl:GetMap():IsPauseGame()
end

-- 准备完毕
function LBlockMiniGameObj:IsReady()
    return self._isReady
end

-- 有效的 (已加载完，未死亡)
function LBlockMiniGameObj:IsValid()
    return self:IsReady() and not self:IsDead()
end

-- 防御塔
function LBlockMiniGameObj:IsTower()
    return self._objType == LBlockMiniGameConst.ObjType.Tower
end

-- 我方
function LBlockMiniGameObj:IsSelf()
    return self._side == LBlockMiniGameConst.Side.Self
end

-- 怪物
function LBlockMiniGameObj:IsMonster()
    return self._objType == LBlockMiniGameConst.ObjType.Monster
end

-- update
function LBlockMiniGameObj:Update(dt)
    if self._needJumpFishCallback then
        self._needJumpFishCallback = nil
        self:JumpFinish()
        return
    end

    if not self:IsReady() then
        return
    end

    for k, v in ipairs(self._actorList) do
        v:Update(dt)
    end

    self:UpdateBattle(dt)
end

-- 暂停游戏
function LBlockMiniGameObj:OnPauseGame()
    for k, v in ipairs(self._actorList) do
        v:OnPauseGame()
    end
end

-- 恢复游戏
function LBlockMiniGameObj:OnResumeGame()
    for k, v in ipairs(self._actorList) do
        v:OnResumeGame()
    end
    if self._needResumeMove then
        self._needResumeMove = nil
        self:GetMoveActor():StartMove()
    end
end

-- region 战斗相关----------------------------------------------------
-- update battle
function LBlockMiniGameObj:UpdateBattle(dt)
    if self._bloodHideTime then
        self._bloodHideTime = self._bloodHideTime - dt
        if self._bloodHideTime <= 0 then
            self._bloodStick:SetVisible(false)
            self._bloodHideTime = nil
        end
    end
end

-- 获取正在攻击的对象, nil表示没有
function LBlockMiniGameObj:GetAttackingObj()
    local obj = self._ctrl:GetObjByKey(self._attackingObjKey)
    if obj and not obj:IsDead() then
        return obj
    end
    return nil
end

-- 设置正在攻击的对象, 只存key
function LBlockMiniGameObj:SetAttackingObj(obj)
    self._attackingObjKey = obj:GetKey()
end

-- 有效的对象进入攻击范围
function LBlockMiniGameObj:SetInAttackRangeObjs(objList)
    if self:IsJumping() then
        return
    end

    if self:IsPauseGame() then
        return
    end
    local atkActor = self:GetAtkActor()
    if atkActor:IsWaiting() then
        return
    end


    if #objList == 0 then
        -- todo:可以优化
        -- if self._lastAtk then
        self._lastAtk = nil
        self:GetMoveActor():ResumeMove()
        self:GetAniActor():PlayRun()
        self:RectifyEnemyObjDis(nil)
        -- end
        return
    end
    self:GetMoveActor():PauseMove()

    local list = {}
    for i, obj in ipairs(objList) do
        table.insert(list, { obj = obj, dis = self:GetDisTo(obj), hp = obj:GetData():GetCurHp(), index = i })
    end
    table.sort(list, SortAtkObjs)

    local hurtObjs, hurtTime, atkSkillRef, isSkill
    if not atkActor:IsSpeSkillCd() then
        -- 特技
        hurtObjs, hurtTime, atkSkillRef = atkActor:DoSkillAtk(list)
        isSkill = true
    elseif not atkActor:IsComSkillCd() then
        -- 普击
        isSkill = false
        hurtObjs, hurtTime, atkSkillRef = atkActor:DoComAtk(list)
    end

    if hurtObjs then
        self._lastAtk = true
        self:RectifyEnemyObjDis(hurtObjs)

        local resName = atkSkillRef.hitEffect

        local LFightIdleConst = LFightIdleConst
        -- 受击
        for _, v in ipairs(hurtObjs) do
            local obj = v
            obj:GetHurtActor():DoHurt(resName, hurtTime, function()
                local hurtNum, isCrit = self:GetData():CalculateAtkHurt(isSkill, obj:GetData())
                local changeType = LFightIdleConst.HUD_HURT
                if isCrit then
                    changeType = LFightIdleConst.HP_TYPE_CRIT
                elseif isSkill then
                    changeType = LFightIdleConst.HUD_HURT_HERO
                end

                obj:SetBloodStickHurt(hurtNum, changeType)
            end)
        end
    end
end

-- 敌方怪物攻击朝向校正
function LBlockMiniGameObj:RectifyEnemyObjDis(hurtObjs)
    if self:IsSelf() or self:IsTower() then
        return
    end

    if not hurtObjs then
        -- 还原
        if self._oldFlipX ~= nil then
            self:UpDateFlipX(self._oldFlipX)
            self._oldFlipX = nil
        end
        return
    end

    local tarObj = hurtObjs[1]
    local myPos = self:GetTransform().position
    local tarFirstPos = tarObj:GetMoveActor():GetFirstPos()

    if math.abs(myPos.y - tarFirstPos.y) > 1 then
        return
    end
    local mydp = self:GetDpObject()
    if self._oldFlipX == nil then
        self._oldFlipX = mydp:IsFlipX()
    end

    local tarPos = tarObj:GetTransform().position

    if myPos.x > tarPos.x then
        self:UpDateFlipX(true)
    else
        self:UpDateFlipX(false)
    end
end

-- 死亡
function LBlockMiniGameObj:IsDead()
    return self._data:IsDead()
end

-- true：表示在自己的攻击范围内
function LBlockMiniGameObj:InAttackRange(obj)
    if obj:IsTower() and self:GetMoveActor():IsInEnd() then
        return true
    end

    local atkDis = self._data:GetAtkDis()
    local dis = self:GetDisTo(obj)
    return atkDis >= dis
end

-- 与另一个对象距离
function LBlockMiniGameObj:GetDisTo(obj)
    local va = obj:GetDpObject():GetPos()
    local vb = self:GetDpObject():GetPos()

    return (va.x - vb.x) ^ 2 + (va.y - vb.y) ^ 2
end

-- endregion ----------------------------------------------------

return LBlockMiniGameObj
